import { getErrorMessage, isAbortLikeError, isRetryableUsageError } from "./errors";
import { pickBestAccount } from "./selection";
import { sleepWithSignal } from "./retry";
import {
	getNextResetAt,
	isUsageUntouched,
	type CodexUsageSnapshot,
} from "./usage";
import { createCodexUsageClient, type CodexUsageClient } from "./usage-client";
import {
	ensureCanonicalStorageData,
	migrateStorageData,
	type StorageAdapter,
} from "./storage";
import type { Account, StorageData } from "./types";

export interface RefreshTokenResult {
	access: string;
	refresh: string;
